const input = $input.first().json;
const body = input.body ?? input;
const headers = input.headers ?? {};
const expectedKey = $env.TRAVELLEDGER_AI_WEBHOOK_KEY || '';
const providedKey = headers['x-travelledger-ai-key'] || headers['X-TravelLedger-AI-Key'] || '';

if (expectedKey && providedKey !== expectedKey) {
  return [{ json: { skipLlm: true, ok: false, error: 'TravelLedger AI \uC6F9\uD6C5 \uC778\uC99D \uD0A4\uAC00 \uC77C\uCE58\uD558\uC9C0 \uC54A\uC2B5\uB2C8\uB2E4.' } }];
}

const llmBaseUrl = ($env.LOCAL_LLM_BASE_URL || '').trim();
if (!llmBaseUrl) {
  return [{ json: { skipLlm: true, ok: false, error: 'TravelLedger AI \uBD84\uC11D\uC5D0 \uC0AC\uC6A9\uD560 LOCAL_LLM_BASE_URL\uC774 \uC124\uC815\uB418\uC9C0 \uC54A\uC558\uC2B5\uB2C8\uB2E4.' } }];
}

const compact = {
  mode: body.mode,
  periodType: body.periodType,
  comparisonPreset: body.comparisonPreset,
  from: body.from,
  to: body.to,
  compareFrom: body.compareFrom,
  compareTo: body.compareTo,
  overview: body.overview,
  categoryBreakdown: body.categoryBreakdown,
  paymentBreakdown: body.paymentBreakdown,
  expensePaymentBreakdown: body.expensePaymentBreakdown,
  periodComparison: body.periodComparison,
  topExpenses: body.topExpenses,
  recurringExpenseCandidates: body.recurringExpenseCandidates,
  comparisonOverview: body.comparisonOverview,
  comparisonCategoryBreakdown: body.comparisonCategoryBreakdown,
  comparisonPaymentBreakdown: body.comparisonPaymentBreakdown,
  comparisonExpenseEntries: body.comparisonExpenseEntries,
};

const prompt = [
  'You are a Korean household ledger analyst for TravelLedger.',
  'Analyze only the provided ledger JSON. Do not invent missing transactions or private facts.',
  'Return JSON only. Every natural-language field must be written in Korean.',
  body.outputContract || '',
  'Ledger dataset:',
  JSON.stringify(compact)
].join('\n\n');

return [{
  json: {
    skipLlm: false,
    model: body.model || $env.LOCAL_LLM_MODEL || 'gemma4:e12b',
    llmBaseUrl,
    prompt,
  }
}];

function fallback(value, fallbackValue) {
  return value == null ? fallbackValue : value;
}

function text(value, fallbackValue = '') {
  return typeof value === 'string' && value.trim() ? value.trim() : fallbackValue;
}

function list(value, fallbackValue = []) {
  if (Array.isArray(value)) {
    return value.filter((item) => typeof item === 'string' && item.trim()).map((item) => item.trim());
  }
  return fallbackValue;
}

const raw = $input.first().json;
if (raw.ok === false) {
  return [{ json: raw }];
}

const content = raw.choices?.[0]?.message?.content ?? raw.message?.content ?? raw.content ?? raw.response ?? raw.text ?? raw;
let parsed = content;
if (typeof content === 'string') {
  const trimmed = content.trim().replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/```$/i, '').trim();
  parsed = JSON.parse(trimmed);
}

const sourceReport = parsed.report ?? parsed.analysisReport ?? parsed.spendingReport ?? {};
const normalizedReport = {
  keySummary: text(sourceReport.keySummary ?? sourceReport.key_summary ?? parsed.keySummary ?? parsed.summary),
  fullReport: text(sourceReport.fullReport ?? sourceReport.full_report ?? sourceReport.report ?? parsed.fullReport ?? parsed.reportText),
  averageAmountInsight: text(sourceReport.averageAmountInsight ?? sourceReport.average_amount_insight ?? parsed.averageAmountInsight),
  notableSpending: list(sourceReport.notableSpending ?? sourceReport.notable_spending ?? parsed.notableSpending, list(parsed.highlights, [])),
  regularSpending: list(sourceReport.regularSpending ?? sourceReport.regular_spending ?? parsed.regularSpending, []),
  abnormalSpending: list(sourceReport.abnormalSpending ?? sourceReport.abnormal_spending ?? parsed.abnormalSpending, list(parsed.unusualSpendingInsights ?? parsed.unusual_spending_insights ?? parsed.warnings, [])),
  topPaymentMethod: text(sourceReport.topPaymentMethod ?? sourceReport.top_payment_method ?? parsed.topPaymentMethod),
  subscriptions: list(sourceReport.subscriptions ?? sourceReport.subscriptionInsights ?? parsed.subscriptions ?? parsed.subscriptionInsights, []),
  fixedExpenses: list(sourceReport.fixedExpenses ?? sourceReport.fixed_expenses ?? parsed.fixedExpenses, list(parsed.fixedCostInsights ?? parsed.fixed_cost_insights, [])),
  improvementActions: list(sourceReport.improvementActions ?? sourceReport.improvement_actions ?? parsed.improvementActions, list(parsed.recommendations, [])),
  comparisonFocus: list(sourceReport.comparisonFocus ?? sourceReport.comparison_focus ?? parsed.comparisonFocus ?? parsed.comparisonInsights, list(parsed.trendInsights ?? parsed.trend_insights, [])),
};

return [{
  json: {
    ok: fallback(parsed.ok, true),
    report: normalizedReport,
    summary: text(parsed.summary, normalizedReport.keySummary),
    highlights: list(parsed.highlights, normalizedReport.notableSpending),
    warnings: list(parsed.warnings ?? parsed.risks, normalizedReport.abnormalSpending),
    recommendations: list(parsed.recommendations, normalizedReport.improvementActions),
    categoryInsights: list(parsed.categoryInsights ?? parsed.category_insights, []),
    paymentInsights: list(parsed.paymentInsights ?? parsed.payment_insights, normalizedReport.topPaymentMethod ? [normalizedReport.topPaymentMethod] : []),
    trendInsights: list(parsed.trendInsights ?? parsed.trend_insights, normalizedReport.comparisonFocus),
    unusualSpendingInsights: list(parsed.unusualSpendingInsights ?? parsed.unusual_spending_insights ?? parsed.anomalyInsights, normalizedReport.abnormalSpending),
    fixedCostInsights: list(parsed.fixedCostInsights ?? parsed.fixed_cost_insights ?? parsed.subscriptionInsights, [...normalizedReport.fixedExpenses, ...normalizedReport.subscriptions]),
    nextPeriodForecast: text(parsed.nextPeriodForecast ?? parsed.next_period_forecast ?? parsed.forecast),
    habitAssessment: text(parsed.habitAssessment ?? parsed.habit_assessment)
  }
}];
